dark.customCSS:
/* --- BIOLUMINESCENT GLASSMORPHISM --- */
* {
	border-color: rgba(0, 255, 255, 0.1) !important;
}

/* Glowing Ocean Typography */
.markdown-prose h1, .markdown-prose h2, .markdown-prose h3 {
	color: #00ecff !important;
	text-shadow: 0 0 12px rgba(0, 236, 255, 0.3);
	font-weight: 700;
}

/* Bioluminescent Chat Bubbles */
.markdown-prose {
	background-color: rgba(0, 24, 26, 0.4) !important;
	backdrop-filter: blur(16px) !important;
	-webkit-backdrop-filter: blur(16px) !important;
	border: 1px solid rgba(0, 255, 255, 0.1) !important;
	border-radius: 20px !important;
	padding: 1rem !important;
}

/* Submerged Inputs */
input, textarea, #chat-input-container, .bg-gray-850 {
	background-color: rgba(0, 11, 13, 0.6) !important;
	border: 1px solid rgba(0, 255, 255, 0.2) !important;
	backdrop-filter: blur(10px) !important;
	border-radius: 14px !important;
	transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}
input:focus, textarea:focus, #chat-input-container:focus-within {
	border-color: #00ecff !important;
	box-shadow: 0 0 25px rgba(0, 236, 255, 0.2) !important;
	background-color: rgba(0, 11, 13, 0.8) !important;
}

/* Abyss Gradient Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: linear-gradient(135deg, #00ecff, #006f80) !important;
	border: none !important;
	color: #000b0d !important;
	font-weight: 700 !important;
	border-radius: 24px !important;
	box-shadow: 0 4px 15px rgba(0, 236, 255, 0.25);
	transition: all 0.3s ease;
}
button.bg-blue-500:hover, .bg-black:hover {
	transform: scale(1.04);
	box-shadow: 0 8px 25px rgba(0, 236, 255, 0.4) !important;
}

/* Jellyfish Scrollbar */
::-webkit-scrollbar-thumb {
	background: rgba(0, 236, 255, 0.4) !important;
	border-radius: 10px;
	border: 2px solid transparent;
	background-clip: content-box;
}
::-webkit-scrollbar-track {
	background: transparent !important;
}

dark.canvasScript:
/**
 * Title: Bioluminescent Plankton
 * Description: Glowing organic nodes that float and react to the mouse cursor.
 */

const CONFIG = {
    particleCount: 50,
    baseColor: 'rgba(0, 236, 255, 0.15)',
    glowColor: 'rgba(0, 236, 255, 0.4)',
    repulsionRadius: 180,
    repulsionForce: 0.05
};

let canvas, ctx, width, height;
let plankton = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(w, h) {
    width = w; height = h;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initPlankton();
}

function initPlankton() {
    plankton = [];
    for (let i = 0; i < CONFIG.particleCount; i++) {
        plankton.push({
            x: Math.random() * width,
            y: Math.random() * height,
            ox: Math.random() * width,
            oy: Math.random() * height,
            vx: (Math.random() - 0.5) * 0.5,
            vy: (Math.random() - 0.5) * 0.5,
            size: Math.random() * 8 + 4,
            pulse: Math.random() * Math.PI * 2
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, width, height);

    for (let p of plankton) {
        p.pulse += 0.02;
        let currentSize = p.size + Math.sin(p.pulse) * 3;

        // Repulsion physics
        let dx = mouse.x - p.x;
        let dy = mouse.y - p.y;
        let dist = Math.hypot(dx, dy);

        if (dist < CONFIG.repulsionRadius) {
            let force = (CONFIG.repulsionRadius - dist) / CONFIG.repulsionRadius;
            p.vx -= (dx / dist) * force * CONFIG.repulsionForce;
            p.vy -= (dy / dist) * force * CONFIG.repulsionForce;
        }

        p.x += p.vx;
        p.y += p.vy;
        p.vx *= 0.98; // Friction
        p.vy *= 0.98;

        // Boundary wrap
        if (p.x < -20) p.x = width + 20;
        if (p.x > width + 20) p.x = -20;
        if (p.y < -20) p.y = height + 20;
        if (p.y > height + 20) p.y = -20;

        // Draw soft glowing orb
        let gradient = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, currentSize);
        gradient.addColorStop(0, CONFIG.glowColor);
        gradient.addColorStop(1, 'rgba(0, 236, 255, 0)');

        ctx.beginPath();
        ctx.arc(p.x, p.y, currentSize, 0, Math.PI * 2);
        ctx.fillStyle = gradient;
        ctx.fill();
    }

    requestAnimationFrame(render);
}

